import "./Contact.css";

export default function Contact() {
  return (
    <section id="contact">
      <h2>Contact</h2>
      <p>
        Feel free to reach out to me via email at{" "}
        <a href="mailto:youremail@example.com">youremail@example.com</a> or
        connect with me on{" "}
        <a href="#" target="_blank" rel="noopener noreferrer">
          LinkedIn
        </a>
        .
      </p>
    </section>
  );
}
